    console.log('Data:', data);
  })
  .catch(error => {
    console.error('Error:', error.message);
  });

async function getData() {
  try {
    const response = await fetchData();
    console.log('Data:', response);
  } catch (error) {
    console.error('Error caught:', error.message);
  }
}

